SELECT "file_type", "file_count" FROM (SELECT CASE WHEN "path" ILIKE '%.py' THEN 'Python' WHEN "path" ILIKE '%.c' THEN 'C' WHEN "path" ILIKE '%.ipynb' THEN 'Jupyter Notebook' WHEN "path" ILIKE '%.java' THEN 'Java' WHEN "path" ILIKE '%.js' THEN 'JavaScript' END AS "file_type", COUNT(*) AS "file_count" FROM "GITHUB_REPOS"."SAMPLE_FILES" WHERE LENGTH("path") - LENGTH(REPLACE("path", '/', '')) > 10 AND ("path" ILIKE '%.py' OR "path" ILIKE '%.c' OR "path" ILIKE '%.ipynb' OR "path" ILIKE '%.java' OR "path" ILIKE '%.js') GROUP BY "file_type") AS counts ORDER BY "file_count" DESC LIMIT 1;
